Greedy insertion using weighted cost delta combining distance increase and time window violation penalty with route capacity awareness.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF_COST = 1e18
	orderCount := len(oris)
	if orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	for shipOffset := 0; shipOffset < orderCount; shipOffset++ {
		bestIdx := -1
		bestScore := INF_COST
		oriSt := oris[shipOffset]
		desSt := dess[shipOffset]
		orderLoad := oriSt.Load + desSt.Load
		origCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			origCosts[i] = assign.Cost
			if assign.AddShip(total_ship+shipOffset, oriSt, desSt) {
				assign.GenRoute()
				newCost := assign.Cost
				assign.RemoveShip(total_ship + shipOffset)
				assign.GenRoute()
				if newCost >= 0 {
					timePenalty := 0.0
					if oriSt.TimeStart > 0 || oriSt.TimeEnd > 0 || desSt.TimeStart > 0 || desSt.TimeEnd > 0 {
						baseDis := cal_dis(assign.StationCurrent, oriSt) + cal_dis(oriSt, desSt)
						timeSlack := 0.0
						if oriSt.TimeEnd > 0 {
							timeSlack += float64(oriSt.TimeEnd)
						}
						if desSt.TimeEnd > 0 {
							timeSlack += float64(desSt.TimeEnd)
						}
						if timeSlack == 0 {
							timeSlack = 1000.0
						}
						timePenalty = baseDis / (timeSlack * 0.001 + 1.0)
					}
					loadFactor := 1.0 + float64(orderLoad)*0.01
					score := (newCost - origCosts[i])*loadFactor + timePenalty*10.0
					if score < bestScore {
						bestScore = score
						bestIdx = i
					}
				}
			}
		}
		fallbackIdx := -1
		for i := 0; i < MAXASSIGNS; i++ {
			if i >= dispatch.AssignsLen {
				fallbackIdx = i
				break
			}
			if dispatch.Assigns[i].StationsLen == 0 {
				fallbackIdx = i
				break
			}
		}
		inserted := false
		if bestIdx >= 0 && bestIdx < dispatch.AssignsLen {
			target := &dispatch.Assigns[bestIdx]
			if target.AddShip(total_ship+shipOffset, oriSt, desSt) {
				target.GenRoute()
				if target.Cost >= 0 {
					inserted = true
				} else {
					target.RemoveShip(total_ship + shipOffset)
					target.GenRoute()
				}
			}
		}
		if !inserted {
			if fallbackIdx >= 0 && fallbackIdx < MAXASSIGNS {
				cand := &dispatch.Assigns[fallbackIdx]
				if cand.AddShip(total_ship+shipOffset, oriSt, desSt) {
					cand.GenRoute()
					if fallbackIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = fallbackIdx + 1
					}
					inserted = true
				}
			}
			if !inserted {
				for i := 0; i < MAXASSIGNS; i++ {
					if i >= dispatch.AssignsLen {
						cand := &dispatch.Assigns[i]
						if cand.AddShip(total_ship+shipOffset, oriSt, desSt) {
							cand.GenRoute()
							dispatch.AssignsLen = i + 1
							inserted = true
							break
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

